// ❌ BAD - default strategy checks this component every cycle
@Component({
  selector: 'app-product-list',
  template: `<li *ngFor="let p of products">{{ p.name }}</li>`
})
export class ProductListComponent {
  @Input() products: Product[] = [];
}

// ✅ GOOD - OnPush + signal input means minimal checks
@Component({
  selector: 'app-product-list',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `@for (p of products(); track p.id) { <li>{{ p.name }}</li> }`
})
export class ProductListComponent {
  products = input<Product[]>([]);
}

// ❌ BAD - class-based guard, verbose and outdated
@Injectable({ providedIn: 'root' })
export class AdminGuard implements CanActivate {
  canActivate(): boolean { return inject(AuthService).isAdmin(); }
}

// ✅ GOOD - functional guard with parameterised factory
export const roleGuard = (role: string): CanActivateFn => () => {
  const auth = inject(AuthService);
  return auth.hasRole(role) || inject(Router).createUrlTree(['/access-denied']);
};
// Route: { path: 'admin', canActivate: [roleGuard('ADMIN')], ... }

// ❌ BAD - mergeMap for search causes out-of-order results
this.searchInput.valueChanges.pipe(
  mergeMap(q => this.catalogApi.search(q))
).subscribe(results => this.results = results);

// ✅ GOOD - switchMap cancels stale requests automatically
this.searchInput.valueChanges.pipe(
  debounceTime(300),
  distinctUntilChanged(),
  switchMap(q => this.catalogApi.search(q)),
  catchError(() => of([]))
).subscribe(results => this.results = results);

// ❌ BAD - using effect() to derive state (use computed instead)
const orderCount = signal(0);
const badge = signal('');
effect(() => { badge.set(orderCount() > 0 ? `${orderCount()}` : ''); });

// ✅ GOOD - computed() derives state lazily and is memoised
const orderCount = signal(0);
const badgeLabel = computed(() => orderCount() > 0 ? `${orderCount()}` : '');
// badgeLabel() reads the cached value; recomputes only when orderCount changes

