// ❌ BAD - impure pipe runs every CD cycle for filtering
@Pipe({ name: 'filterOrders', pure: false })
export class FilterOrdersPipe implements PipeTransform {
  transform(orders: Order[], status: string): Order[] {
    return orders.filter(o => o.status === status);
  }
}

// ✅ GOOD - pure pipe with primitive input; memoised automatically
@Pipe({ name: 'currencyFormat', pure: true, standalone: true })
export class CurrencyFormatPipe implements PipeTransform {
  transform(amount: number, currency = 'GBP'): string {
    return new Intl.NumberFormat('en-GB', { style: 'currency', currency }).format(amount);
  }
}

// ❌ BAD - adding auth header in every service method individually
export class OrderService {
  getOrders() {
    const token = this.auth.getToken();
    return this.http.get('/api/orders', { headers: { Authorization: `Bearer ${token}` } });
  }
}

// ✅ GOOD - one interceptor handles all requests centrally
export const authInterceptor: HttpInterceptorFn = (req, next) => {
  const token = inject(AuthService).getToken();
  if (!token) return next(req);
  return next(req.clone({ headers: req.headers.set('Authorization', `Bearer ${token}`) }));
};

