// ❌ BAD - class-based resolver, verbose and outdated
@Injectable({ providedIn: 'root' })
export class PolicyResolver implements Resolve<InsurancePolicy> {
  resolve(route: ActivatedRouteSnapshot) {
    return inject(PolicyService).getPolicy(route.paramMap.get('id')!);
  }
}

// ✅ GOOD - functional resolver with error handling
export const policyResolver: ResolveFn<InsurancePolicy> = (route) => {
  const router = inject(Router);
  return inject(PolicyService).getPolicy(route.paramMap.get('id')!).pipe(
    catchError(() => { router.navigate(['/not-found']); return EMPTY; })
  );
};

