// ❌ BAD - using ElementRef.nativeElement directly (not SSR safe)
@Directive({ selector: '[appHighlight]' })
export class HighlightDirective {
  constructor(private el: ElementRef) {
    this.el.nativeElement.style.backgroundColor = 'yellow';
  }
}

// ✅ GOOD - structural directive using TemplateRef and ViewContainerRef
@Directive({ selector: '[appIfRole]', standalone: true })
export class IfRoleDirective {
  constructor(private tpl: TemplateRef<any>, private vcr: ViewContainerRef) {}
  @Input() set appIfRole(requiredRole: string) {
    const hasRole = inject(AuthService).hasRole(requiredRole);
    hasRole ? this.vcr.createEmbeddedView(this.tpl) : this.vcr.clear();
  }
}

// ❌ BAD - manually querying and modifying the DOM outside Angular's pipeline
@Directive({ selector: '[appDragDrop]' })
export class DragDropDirective implements OnInit {
  ngOnInit() {
    document.querySelector('[appDragDrop]')!.addEventListener('dragover', (e) => {
      (e.target as HTMLElement).classList.add('drag-over');
    });
  }
}

// ✅ GOOD - HostListener and HostBinding keep the directive clean and testable
@Directive({ selector: '[appDragDrop]', standalone: true })
export class DragDropDirective {
  @HostBinding('class.drag-over') isDragOver = false;
  @HostListener('dragover', ['$event']) onDragOver(e: DragEvent) {
    e.preventDefault();
    this.isDragOver = true;
  }
  @HostListener('dragleave') onDragLeave() { this.isDragOver = false; }
}

// ❌ BAD - standalone component created but never added to parent imports
@Component({
  selector: 'app-invoice-badge',
  standalone: true,
  template: `<span class="badge">{{ count }}</span>`
})
export class InvoiceBadgeComponent { count = 0; }
// Parent template uses <app-invoice-badge> but did not add it to imports[]

// ✅ GOOD - standalone component correctly imported by parent
@Component({
  selector: 'app-invoice-badge',
  standalone: true,
  imports: [NgClass],
  template: `<span [ngClass]="badgeClass">{{ count }}</span>`
})
export class InvoiceBadgeComponent {
  @Input() count = 0;
  get badgeClass() { return { 'badge-warning': this.count > 0, 'badge-ok': this.count === 0 }; }
}

