// ❌ BAD - reading @Input in constructor; it is undefined here
export class PolicyDetailComponent {
  @Input() policyId!: string;
  constructor(private policyService: PolicyService) {
    this.policyService.getPolicy(this.policyId); // policyId is undefined
  }
}

// ✅ GOOD - react to policyId changes in ngOnChanges
export class PolicyDetailComponent implements OnChanges {
  @Input() policyId!: string;
  policy?: Policy;
  constructor(private policyService: PolicyService) {}
  ngOnChanges(changes: SimpleChanges) {
    if (changes['policyId']) {
      this.policyService.getPolicy(this.policyId)
        .subscribe(p => this.policy = p);
    }
  }
}

